use crate::errors::MultivariousError;
use crate::common_types::Matrix;
use crate::preprocessing::traits::{Preprocessor, PreprocessConfig};
use serde::{Serialize, Deserialize};
use std::collections::HashMap;

/// A pipeline of preprocessing steps to be applied sequentially
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct PreprocessPipeline {
    steps: Vec<Box<dyn Preprocessor>>,
    cache: HashMap<String, Matrix>,
    config: PreprocessConfig,
}

impl PreprocessPipeline {
    /// Create a new empty pipeline
    pub fn new() -> Self {
        Self {
            steps: Vec::new(),
            cache: HashMap::new(),
            config: PreprocessConfig::default(),
        }
    }

    /// Create a pipeline with specific configuration
    pub fn with_config(config: PreprocessConfig) -> Self {
        Self {
            steps: Vec::new(),
            cache: HashMap::new(),
            config,
        }
    }

    /// Add a preprocessing step to the pipeline
    pub fn add_step(mut self, step: Box<dyn Preprocessor>) -> Self {
        self.steps.push(step);
        self
    }

    /// Get the number of steps in the pipeline
    pub fn len(&self) -> usize {
        self.steps.len()
    }

    /// Check if the pipeline is empty
    pub fn is_empty(&self) -> bool {
        self.steps.is_empty()
    }

    /// Clear the cache
    pub fn clear_cache(&mut self) {
        self.cache.clear();
    }

    /// Get a reference to the steps
    pub fn steps(&self) -> &[Box<dyn Preprocessor>] {
        &self.steps
    }

    /// Get a mutable reference to the steps
    pub fn steps_mut(&mut self) -> &mut Vec<Box<dyn Preprocessor>> {
        &mut self.steps
    }
}

impl Default for PreprocessPipeline {
    fn default() -> Self {
        Self::new()
    }
}

impl Preprocessor for PreprocessPipeline {
    fn fit(&mut self, data: &Matrix) -> Result<(), MultivariousError> {
        let mut current = data.clone();

        for step in &mut self.steps {
            step.fit(&current)?;
            current = step.transform(&current)?;
        }

        Ok(())
    }

    fn transform(&self, data: &Matrix) -> Result<Matrix, MultivariousError> {
        let mut current = data.clone();

        for step in &self.steps {
            current = step.transform(&current)?;
        }

        Ok(current)
    }

    fn inverse_transform(&self, data: &Matrix) -> Result<Matrix, MultivariousError> {
        let mut current = data.clone();

        // Apply inverse transforms in reverse order
        for step in self.steps.iter().rev() {
            current = step.inverse_transform(&current)?;
        }

        Ok(current)
    }

    fn is_fitted(&self) -> bool {
        self.steps.iter().all(|step| step.is_fitted())
    }

    fn name(&self) -> &str {
        "PreprocessPipeline"
    }
}

/// Builder for creating preprocessing pipelines
pub struct PipelineBuilder {
    steps: Vec<Box<dyn Preprocessor>>,
    config: PreprocessConfig,
}

impl PipelineBuilder {
    /// Create a new pipeline builder
    pub fn new() -> Self {
        Self {
            steps: Vec::new(),
            config: PreprocessConfig::default(),
        }
    }

    /// Set the configuration for the pipeline
    pub fn with_config(mut self, config: PreprocessConfig) -> Self {
        self.config = config;
        self
    }

    /// Add a preprocessing step
    pub fn add(mut self, step: Box<dyn Preprocessor>) -> Self {
        self.steps.push(step);
        self
    }

    /// Build the pipeline
    pub fn build(self) -> PreprocessPipeline {
        PreprocessPipeline {
            steps: self.steps,
            cache: HashMap::new(),
            config: self.config,
        }
    }
}

impl Default for PipelineBuilder {
    fn default() -> Self {
        Self::new()
    }
}

/// Support for block-wise preprocessing in multiblock analysis
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct BlockwisePreprocessor {
    /// Preprocessors for each block, indexed by block name
    block_preprocessors: HashMap<String, Box<dyn Preprocessor>>,
    /// Block sizes (number of columns per block)
    block_sizes: HashMap<String, usize>,
    /// Order of blocks
    block_order: Vec<String>,
}

impl BlockwisePreprocessor {
    /// Create a new blockwise preprocessor
    pub fn new() -> Self {
        Self {
            block_preprocessors: HashMap::new(),
            block_sizes: HashMap::new(),
            block_order: Vec::new(),
        }
    }

    /// Add a preprocessor for a specific block
    pub fn add_block(
        mut self, 
        name: String, 
        preprocessor: Box<dyn Preprocessor>,
        n_columns: usize
    ) -> Self {
        self.block_preprocessors.insert(name.clone(), preprocessor);
        self.block_sizes.insert(name.clone(), n_columns);
        self.block_order.push(name);
        self
    }

    /// Get the total number of columns across all blocks
    pub fn total_columns(&self) -> usize {
        self.block_sizes.values().sum()
    }

    /// Split a matrix into blocks based on configured sizes
    fn split_into_blocks(&self, data: &Matrix) -> Result<HashMap<String, Matrix>, MultivariousError> {
        if data.ncols() != self.total_columns() {
            return Err(MultivariousError::DimensionMismatch {
                expected: self.total_columns().to_string(),
                actual: data.ncols().to_string(),
            });
        }

        let mut blocks = HashMap::new();
        let mut col_start = 0;

        for block_name in &self.block_order {
            let n_cols = self.block_sizes[block_name];
            let block_data = data.slice(ndarray::s![.., col_start..col_start + n_cols]).to_owned();
            blocks.insert(block_name.clone(), block_data);
            col_start += n_cols;
        }

        Ok(blocks)
    }

    /// Concatenate blocks back into a single matrix
    fn concatenate_blocks(&self, blocks: HashMap<String, Matrix>) -> Result<Matrix, MultivariousError> {
        let mut columns = Vec::new();

        for block_name in &self.block_order {
            let block = blocks.get(block_name)
                .ok_or_else(|| MultivariousError::PreprocessingError(
                    format!("Missing block: {}", block_name)
                ))?;

            for col in block.axis_iter(ndarray::Axis(1)) {
                columns.push(col.to_owned());
            }
        }

        if columns.is_empty() {
            return Err(MultivariousError::PreprocessingError(
                "No columns to concatenate".to_string()
            ));
        }

        let n_rows = columns[0].len();
        let n_cols = columns.len();
        let mut result = Matrix::zeros((n_rows, n_cols));

        for (col_idx, col) in columns.iter().enumerate() {
            result.column_mut(col_idx).assign(col);
        }

        Ok(result)
    }
}

impl Default for BlockwisePreprocessor {
    fn default() -> Self {
        Self::new()
    }
}

impl Preprocessor for BlockwisePreprocessor {
    fn fit(&mut self, data: &Matrix) -> Result<(), MultivariousError> {
        let blocks = self.split_into_blocks(data)?;

        for (block_name, block_data) in blocks {
            if let Some(preprocessor) = self.block_preprocessors.get_mut(&block_name) {
                preprocessor.fit(&block_data)?;
            }
        }

        Ok(())
    }

    fn transform(&self, data: &Matrix) -> Result<Matrix, MultivariousError> {
        let blocks = self.split_into_blocks(data)?;
        let mut transformed_blocks = HashMap::new();

        for (block_name, block_data) in blocks {
            if let Some(preprocessor) = self.block_preprocessors.get(&block_name) {
                let transformed = preprocessor.transform(&block_data)?;
                transformed_blocks.insert(block_name, transformed);
            }
        }

        self.concatenate_blocks(transformed_blocks)
    }

    fn inverse_transform(&self, data: &Matrix) -> Result<Matrix, MultivariousError> {
        let blocks = self.split_into_blocks(data)?;
        let mut inverse_blocks = HashMap::new();

        for (block_name, block_data) in blocks {
            if let Some(preprocessor) = self.block_preprocessors.get(&block_name) {
                let inverse = preprocessor.inverse_transform(&block_data)?;
                inverse_blocks.insert(block_name, inverse);
            }
        }

        self.concatenate_blocks(inverse_blocks)
    }

    fn is_fitted(&self) -> bool {
        self.block_preprocessors.values().all(|p| p.is_fitted())
    }

    fn name(&self) -> &str {
        "BlockwisePreprocessor"
    }
}

