            [7.0, 8.0, 9.0, 70.0, 80.0, 90.0]
        ];

        let mut blockwise = BlockwisePreprocessor::new()
            .add_block("block1".to_string(), Box::new(Center::new()), 3)
            .add_block("block2".to_string(), Box::new(Standardize::new()), 3);

        blockwise.fit(&data).unwrap();
        let transformed = blockwise.transform(&data).unwrap();

        // First block should be centered, second block should be standardized
        assert_eq!(transformed.shape(), data.shape());

        // Check that first 3 columns are centered (mean = 0)
        for col in 0..3 {
            let col_mean = transformed.column(col).mean().unwrap();
            assert!(col_mean.abs() < 1e-10);
        }

        // Check that last 3 columns are standardized (mean = 0, std = 1)
        for col in 3..6 {
            let col_data = transformed.column(col);
            let col_mean = col_data.mean().unwrap();
            let col_std = col_data.std(1.0);
            assert!(col_mean.abs() < 1e-10);
            assert!((col_std - 1.0).abs() < 1e-10);
        }
    }

    #[test]
    fn test_pipeline_builder() {
        let pipeline = PipelineBuilder::new()
            .with_config(PreprocessConfig { by_column: false })
            .add(Box::new(Center::new()))
            .add(Box::new(Scale::new()))
            .build();

        assert_eq!(pipeline.len(), 2);
        assert!(!pipeline.is_empty());
    }
}

