use crate::errors::MultivariousError;
use crate::common_types::{Matrix, Vector};
use std::fmt::Debug;

/// Core trait for projection operations
pub trait Project: Send + Sync + Debug {
    /// Project data onto learned components
    /// 
    /// # Arguments
    /// * `data` - Input data matrix (n_samples x n_features)
    /// 
    /// # Returns
    /// Projected data matrix (n_samples x n_components)
    fn project(&self, data: &Matrix) -> Result<Matrix, MultivariousError>;

    /// Get the number of components in the projection
    fn n_components(&self) -> usize;

    /// Get the number of features expected in input data
    fn n_features(&self) -> usize;

    /// Check if the projector has been fitted
    fn is_fitted(&self) -> bool;

    /// Get the name of the projector
    fn name(&self) -> &str;
}

/// Trait for reconstruction from projected space
pub trait Reconstruct: Project {
    /// Reconstruct data from projected space back to original space
    /// 
    /// # Arguments
    /// * `projected` - Projected data matrix (n_samples x n_components)
    /// 
    /// # Returns
    /// Reconstructed data matrix (n_samples x n_features)
    fn reconstruct(&self, projected: &Matrix) -> Result<Matrix, MultivariousError>;

    /// Calculate reconstruction error for given data
    fn reconstruction_error(&self, data: &Matrix) -> Result<f64, MultivariousError> {
        let projected = self.project(data)?;
        let reconstructed = self.reconstruct(&projected)?;
        let diff = data - &reconstructed;
        Ok(diff.mapv(|x| x * x).sum().sqrt())
    }
}

/// Trait for partial projection operations (subset of components)
pub trait PartialProject: Project {
    /// Project data onto a subset of components
    /// 
    /// # Arguments
    /// * `data` - Input data matrix
    /// * `component_indices` - Indices of components to project onto
    /// 
    /// # Returns
    /// Projected data using only specified components
    fn project_components(
        &self, 
        data: &Matrix, 
        component_indices: &[usize]
    ) -> Result<Matrix, MultivariousError>;

    /// Get the importance/variance explained by each component
    fn component_importance(&self) -> Result<Vector, MultivariousError>;

    /// Select top k components by importance
    fn select_top_components(&self, k: usize) -> Result<Vec<usize>, MultivariousError> {
        let importance = self.component_importance()?;
        let mut indices: Vec<usize> = (0..importance.len()).collect();
        indices.sort_by(|&a, &b| {
            importance[b].partial_cmp(&importance[a]).unwrap_or(std::cmp::Ordering::Equal)
        });
        Ok(indices.into_iter().take(k).collect())
    }
}

/// Trait for transposing projection models
pub trait Transpose: Project {
    /// Type of the transposed model
    type Transposed: Project;

    /// Create a transposed version of the projector
    /// 
    /// This is useful for switching between projecting samples vs features
    fn transpose(&self) -> Result<Self::Transposed, MultivariousError>;
}

/// Helper trait for creating projector trait objects
pub trait ProjectorObject: Project {
    /// Clone the projector as a trait object
    fn clone_box(&self) -> Box<dyn ProjectorObject>;
}

impl<T> ProjectorObject for T
where
    T: Project + Clone + 'static,
{
    fn clone_box(&self) -> Box<dyn ProjectorObject> {
        Box::new(self.clone())
    }
}

/// Builder pattern for creating projectors
pub trait ProjectorBuilder: Send + Sync {
    /// Type of projector this builder creates
    type Projector: Project;

    /// Build the projector
    fn build(self) -> Result<Self::Projector, MultivariousError>;
}

/// Configuration options common to many projectors
#[derive(Debug, Clone)]
pub struct ProjectorConfig {
    /// Number of components to retain
    pub n_components: Option<usize>,
    /// Whether to center data before projection
    pub center: bool,
    /// Whether to scale data before projection
    pub scale: bool,
    /// Random seed for reproducibility
    pub random_state: Option<u64>,
    /// Maximum number of iterations for iterative methods
    pub max_iter: Option<usize>,
    /// Convergence tolerance
    pub tolerance: Option<f64>,
}

impl Default for ProjectorConfig {
    fn default() -> Self {
        Self {
            n_components: None,
            center: true,
            scale: false,
            random_state: None,
            max_iter: Some(1000),
            tolerance: Some(1e-6),
        }
    }
}

