            if projected.ncols() != self.n_components {
                return Err(MultivariousError::DimensionMismatch {
                    expected: self.n_components.to_string(),
                    actual: projected.ncols().to_string(),
                });
            }

            // Simple reconstruction: pad with zeros
            let n_samples = projected.nrows();
            let mut reconstructed = Matrix::zeros((n_samples, self.n_features));
            reconstructed.slice_mut(ndarray::s![.., ..self.n_components])
                .assign(projected);
            Ok(reconstructed)
        }
    }

