            component_indices: &[usize]
        ) -> Result<Matrix, MultivariousError> {
            if data.ncols() != self.n_features {
                return Err(MultivariousError::DimensionMismatch {
                    expected: self.n_features.to_string(),
                    actual: data.ncols().to_string(),
                });
            }

            // Check indices are valid
            for &idx in component_indices {
                if idx >= self.n_components {
                    return Err(MultivariousError::InvalidParameter(
                        format!("Component index {} out of bounds", idx)
                    ));
                }
            }

            // Project and select components
            let projected = self.project(data)?;
            let selected_cols: Vec<_> = component_indices.iter()
                .map(|&idx| projected.column(idx).to_owned())
                .collect();

            if selected_cols.is_empty() {
                return Ok(Matrix::zeros((data.nrows(), 0)));
            }

            Ok(ndarray::stack(ndarray::Axis(1), &selected_cols)
                .map_err(|e| MultivariousError::PreprocessingError(e.to_string()))?)
        }

        fn component_importance(&self) -> Result<Vector, MultivariousError> {
            // Mock importance: decreasing values
            Ok(Vector::from_iter((0..self.n_components)
                .map(|i| 1.0 / (i + 1) as f64)))
        }
    }

    #[test]
    fn test_project_trait() {
        let projector = MockProjector {
            n_components: 2,
            n_features: 4,
        };

